    24	export {
    25	  beamGripProvider,
    26	  columnGripProvider,
    27	  dimensionGripProvider,
    28	  doorGripProvider,
    29	  floorGripProvider,
    30	  maskingRegionGripProvider,
    31	  referencePlaneGripProvider,
    32	  sectionCutGripProvider,
    33	  windowGripProvider,
    34	};
